--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ ... @@
+// ─── Room transition animation system ───────────────────────────────
+
+interface TransitionState {
+  active: boolean;
+  fromType: CharacterType | null;
+  toType: CharacterType | null;
+  progress: number; // 0 to 1
+  duration: number; // in ms
+  effect: 'fade' | 'slide';
+  startTime: number;
+  easing: (t: number) => number;
+}
+
+const transitionState: TransitionState = {
+  active: false,
+  fromType: null,
+  toType: null,
+  progress: 0,
+  duration: 600,
+  effect: 'fade',
+  startTime: 0,
+  easing: (t) => t, // linear default
+};
+
+/**
+ * Easing function: easeInOutQuad
+ * Smooth acceleration and deceleration
+ */
+function easeInOutQuad(t: number): number {
+  return t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;
+}
+
+/**
+ * Starts a room transition animation from current room to target room.
+ * @param fromType Current room CharacterType
+ * @param toType Target room CharacterType
+ * @param effect Transition effect: 'fade' or 'slide'
+ * @param duration Duration in milliseconds (default 600)
+ */
+export function transitionToRoom(
+  fromType: CharacterType,
+  toType: CharacterType,
+  effect: 'fade' | 'slide' = 'fade',
+  duration = 600,
+) {
+  if (transitionState.active) {
+    // If a transition is already active, ignore or restart
+    // For simplicity, restart transition
+  }
+  transitionState.active = true;
+  transitionState.fromType = fromType;
+  transitionState.toType = toType;
+  transitionState.progress = 0;
+  transitionState.duration = duration;
+  transitionState.effect = effect;
+  transitionState.startTime = performance.now();
+  transitionState.easing = easeInOutQuad;
+}
+
+/**
+ * Updates the transition progress based on current time.
+ * Returns true if transition is active, false if finished.
+ * @param now Current timestamp in ms
+ */
+export function updateTransition(now: number): boolean {
+  if (!transitionState.active) return false;
+  const elapsed = now - transitionState.startTime;
+  transitionState.progress = Math.min(elapsed / transitionState.duration, 1);
+  if (transitionState.progress >= 1) {
+    transitionState.active = false;
+  }
+  return transitionState.active;
+}
+
+/**
+ * Renders the room transition animation on given canvas context.
+ * @param ctx CanvasRenderingContext2D
+ * @param x X position of room rendering
+ * @param y Y position of room rendering
+ * @param w Width of room rendering
+ * @param h Height of room rendering
+ * @param frame Current animation frame count
+ */
+export function renderRoomTransition(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  w: number,
+  h: number,
+  frame: number,
+) {
+  if (!transitionState.active || !transitionState.fromType || !transitionState.toType) return;
+  const t = transitionState.easing(transitionState.progress);
+  if (transitionState.effect === 'fade') {
+    // Draw from room with decreasing opacity
+    ctx.save();
+    ctx.globalAlpha = 1 - t;
+    drawRoom(ctx, transitionState.fromType, x, y, w, h, frame);
+    ctx.restore();
+
+    // Draw to room with increasing opacity
+    ctx.save();
+    ctx.globalAlpha = t;
+    drawRoom(ctx, transitionState.toType, x, y, w, h, frame);
+    ctx.restore();
+  } else if (transitionState.effect === 'slide') {
+    // Slide from left to right
+    const offsetX = lerp(0, w, t);
+    // Draw from room sliding out to left
+    ctx.save();
+    ctx.beginPath();
+    ctx.rect(x - offsetX, y, w, h);
+    ctx.clip();
+    drawRoom(ctx, transitionState.fromType, x - offsetX, y, w, h, frame);
+    ctx.restore();
+
+    // Draw to room sliding in from right
+    ctx.save();
+    ctx.beginPath();
+    ctx.rect(x + w - offsetX, y, w, h);
+    ctx.clip();
+    drawRoom(ctx, transitionState.toType, x + w - offsetX, y, w, h, frame);
+    ctx.restore();
+  }
+}
+
